const datos = $('Consultar datos principales').first().json;
const compromisosPorTarjeta = $input.all().filter(i => i.json.tarjeta).map(i => i.json);

const TC = Number(datos.tc);
const saldoOperativo = Number(datos.saldo_operativo || 0);
const ingresoUSD = Number(datos.ingreso_usd || 1500);
const ingresoARS = Math.round(ingresoUSD * TC);
const totalCompromisosTc = Number(datos.total_compromisos_tc || 0);
const subsUSD = Number(datos.subs_usd || 0);
const totalPreviosSueldo = Number(datos.total_previos_sueldo || 0);
const detallePrevios = datos.detalle_previos || '';

// Fondos de ahorro — activos desde Mayo 2026 (Santander cancelado)
const fondoAuto = 200000;
const fondoIndependencia = 165000;
const totalAhorro = fondoAuto + fondoIndependencia;
const totalNecesario = totalCompromisosTc + totalAhorro;

// --- Calcular fecha estimada de cobro ---
const hoy = new Date();
let añoProx = hoy.getFullYear();
let mesProx = hoy.getMonth() + 1;
if (mesProx > 11) { mesProx = 0; añoProx++; }

function primerJuevesHabil(año, mes) {
  let d = new Date(año, mes, 1);
  while (d.getDay() !== 4) d.setDate(d.getDate() + 1);
  const toKey = dt =>
    `${dt.getFullYear()}-${String(dt.getMonth()+1).padStart(2,'0')}-${String(dt.getDate()).padStart(2,'0')}`;
  const holidays = new Set([
    `${año}-01-01`, `${año}-01-06`, `${año}-05-01`,
    `${año}-08-15`, `${año}-10-12`, `${año}-11-01`,
    `${año}-12-06`, `${año}-12-08`, `${año}-12-25`,
    `${año}-02-28`,
    '2026-04-02', '2026-04-03',
    '2027-04-01', '2027-04-02',
  ]);
  while (holidays.has(toKey(d))) d.setDate(d.getDate() + 7);
  return d;
}

const juevesEspaña = primerJuevesHabil(añoProx, mesProx);
const fechaMin = new Date(juevesEspaña); fechaMin.setDate(fechaMin.getDate() + 3);
const fechaMax = new Date(juevesEspaña); fechaMax.setDate(fechaMax.getDate() + 5);

const meses = ['Enero','Febrero','Marzo','Abril','Mayo','Junio','Julio','Agosto','Septiembre','Octubre','Noviembre','Diciembre'];
const dias = ['Dom','Lun','Mar','Mié','Jue','Vie','Sáb'];
const fmt = n => Math.round(Number(n)).toLocaleString('es-AR');
const fmtF = d => `${dias[d.getDay()]} ${d.getDate()} ${meses[d.getMonth()]}`;

const mesProxNombre = meses[mesProx];
const coberturaPrevia = saldoOperativo - totalPreviosSueldo;
const sobrante = ingresoARS - totalNecesario;

let msg = `📅 *PREPARACIÓN ${mesProxNombre.toUpperCase()}*\n`;
msg += `━━━━━━━━━━━━━━━━\n\n`;

msg += `💵 *COBRO ESTIMADO*\n`;
msg += `España paga: ${fmtF(juevesEspaña)}\n`;
msg += `Te llega: ${fmtF(fechaMin)} – ${fmtF(fechaMax)}\n`;
msg += `U$D ${fmt(ingresoUSD)} × $${fmt(TC)} = *$${fmt(ingresoARS)}*\n\n`;

msg += `⚠️ *ANTES DEL SUELDO (días 1–13)*\n`;
if (detallePrevios) {
  for (const l of detallePrevios.split('\n')) if (l.trim()) msg += `  ${l}\n`;
}
msg += `  *Total: $${fmt(totalPreviosSueldo)}*\n`;
msg += `  Operativo hoy: $${fmt(saldoOperativo)}\n`;
msg += coberturaPrevia >= 0
  ? `  ✅ Cubierto (sobran $${fmt(coberturaPrevia)})\n\n`
  : `  🔴 *Falta $${fmt(Math.abs(coberturaPrevia))} antes de cobrar*\n\n`;

msg += `💳 *COMPROMISOS TARJETAS*\n`;
for (const c of compromisosPorTarjeta) {
  const t = c.tarjeta.toUpperCase();
  const label = t.includes('GALICIA') ? '🏦 Galicia'
              : t.includes('NARANJA') ? '🟠 Naranja'
              : c.tarjeta;
  msg += `  ${label}: *$${fmt(c.total)}*\n`;
  if (c.items) msg += `  _${c.items}_\n`;
}
if (compromisosPorTarjeta.length === 0) msg += `  Sin compromisos activos\n`;
msg += `  *Total TC: $${fmt(totalCompromisosTc)}*\n`;
if (subsUSD > 0) msg += `  + U$D ${fmt(subsUSD)} suscripciones\n`;
msg += `\n`;

msg += `💰 *AHORRO DEL MES*\n`;
msg += `  🚗 Fondo Auto: $${fmt(fondoAuto)}\n`;
msg += `  📈 Fondo Independencia: $${fmt(fondoIndependencia)}\n`;
msg += `  *Total: $${fmt(totalAhorro)}*\n\n`;

msg += `━━━━━━━━━━━━━━━━\n`;
msg += `📊 *TOTAL A RESERVAR*\n`;
msg += `  ARS: *$${fmt(totalNecesario)}*\n`;
if (subsUSD > 0) msg += `  USD: *U$D ${fmt(subsUSD)}*\n`;
msg += `\n`;
msg += sobrante >= 0
  ? `✅ Libre para variables: *$${fmt(sobrante)}*`
  : `⚠️ Déficit proyectado: *$${fmt(Math.abs(sobrante))}*`;

return [{ json: { mensaje: msg } }];
